<?php
declare(strict_types=1);
$root=require dirname(__DIR__).'/bootstrap/app.php';
use Dompdf\Dompdf;use Dompdf\Options;use Vigilancia\Database\Connection;use Vigilancia\Repositories\PermissionRepository;use Vigilancia\Repositories\ReportRepository;use Vigilancia\Repositories\SecurityLogRepository;use Vigilancia\Services\AuthService;use Vigilancia\Services\ReportService;use Vigilancia\Support\ClientInfo;use Vigilancia\Support\Config;use Vigilancia\Support\Session;
Session::start();$pdo=Connection::make(Config::database());$auth=new AuthService($pdo);$actor=$auth->current();$service=new ReportService(new ReportRepository($pdo),new PermissionRepository($pdo),new SecurityLogRepository($pdo));$data=$service->report($actor,(int)($_GET['id']??0));$r=$data['report'];$e=static fn($v)=>htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');
$rows=$data['rows'];$headers=$rows?array_keys($rows[0]):[];$table='<p class="muted">Sin registros para los filtros seleccionados.</p>';if($rows){$table='<table><thead><tr>'.implode('',array_map(fn($h)=>'<th>'.$e(str_replace('_',' ',$h)).'</th>',$headers)).'</tr></thead><tbody>';foreach($rows as$row){$table.='<tr>';foreach($headers as$h)$table.='<td>'.$e(is_scalar($row[$h]??null)?$row[$h]:'').'</td>';$table.='</tr>';}$table.='</tbody></table>';}
$appUrl=Config::app()['url'];$evidence='';foreach(array_slice($data['evidence'],0,30)as$file){$path=$root.'/'.$file['file_path'];if($file['media_type']==='photo'&&is_file($path))$evidence.='<figure><img src="data:'.$file['mime_type'].';base64,'.base64_encode((string)file_get_contents($path)).'"><figcaption>Evento #'.$e($file['event_id']).' · '.$e($file['captured_at']).'</figcaption></figure>';else$evidence.='<p>Video del evento #'.$e($file['event_id']).': <a href="'.$e($appUrl.'/event-evidence.php?id='.$file['id']).'">enlace protegido</a></p>';}
